#!/usr/bin/env bash
# Generated by @navori/plugin-semgrep. Runs semgrep over TS/TSX files changed
# vs `{{branchBase}}` with the `auto` ruleset. Skips silently if semgrep or
# git are absent — the tool is optional.
#
# Triggered as a PreToolUse(Bash) hook (gated to git commit/push) and as a
# Stop hook (runs unconditionally at session close).

set -euo pipefail

# PreToolUse(Bash) passes the command — gate to commit/push. The Stop hook
# passes no command — run unconditionally at session close.
cmd=$(jq -r '.tool_input.command // empty' 2>/dev/null || true)
if [ -n "$cmd" ]; then
  case "$cmd" in
    'git commit'*|'git push'*) ;;
    *) exit 0 ;;
  esac
fi

if ! command -v semgrep >/dev/null 2>&1; then
  echo "⊘ semgrep no instalado localmente — skip (install: brew install semgrep)" >&2
  exit 0
fi

if ! git rev-parse --git-dir >/dev/null 2>&1; then
  exit 0
fi

if ! git rev-parse --verify {{branchBase}} >/dev/null 2>&1; then
  echo "⊘ branch '{{branchBase}}' no existe localmente — skip semgrep" >&2
  exit 0
fi

# Run from the repo root so changed paths stay relative — robust to spaces in
# the repo's absolute path. NUL-delimited read handles spaces in filenames too.
# The `-- '*.ts' '*.tsx'` pathspec filters by extension without a pipe.
cd "$(git rev-parse --show-toplevel)"

files=()
while IFS= read -r -d '' f; do
  files+=("$f")
done < <(git diff --name-only -z --diff-filter=ACMRT {{branchBase}} -- '*.ts' '*.tsx' 2>/dev/null)

if [ ${#files[@]} -eq 0 ]; then
  echo "✓ semgrep: sin cambios vs {{branchBase}}" >&2
  exit 0
fi

echo "▶ semgrep: ${#files[@]} archivo(s) modificados vs {{branchBase}}" >&2

semgrep scan \
  --config=auto \
  --error \
  --metrics=off \
  "${files[@]}"
